function Sliders() {
    let SlidersArray = []

    let sliders = document.querySelectorAll(".slider")
    sliders.forEach((slider,index) => {
        slider.setAttribute("data-slider-id",index)

        let isLoop = slider.classList.contains("_loop")

        SlidersArray[index] = new Swiper(`.slider[data-slider-id="${index}"] .swiper-container`, {
            slidesPerView: "auto",
            spaceBetween: 0,
            watchSlidesProgress: true,
            preventClicks :true,
            a11y: false,
            observer: true,
            observeParents: true,
            observeSlideChildren: true,
            loop: isLoop,
            navigation: {
                nextEl: `.slider[data-slider-id="${index}"] .swiper-button-next`,
                prevEl: `.slider[data-slider-id="${index}"] .swiper-button-prev`,
            },
            pagination: {
                el: `.slider[data-slider-id="${index}"] .swiper-pagination`,
                type: 'bullets',
                clickable: true,
            },
            on: {
                init: function () {
                    if(slider.classList.contains("projects-slider")){
                        this.slideTo(1,0)
                    }
                }
            }
        })
    })
}

function gallery() {
    let SlidersArray = []

    let sliders = document.querySelectorAll(".gallery")
    sliders.forEach((slider,index) => {
        slider.setAttribute("data-slider-id",index)
        let gallery = {
            mySwiper: {},
            mySwiper2: {}
        }

        gallery.mySwiper = new Swiper(`.gallery[data-slider-id="${index}"] .mySwiper`, {
            spaceBetween: 0,
            slidesPerView: "auto",
            freeMode: true,
            watchSlidesProgress: true,
            direction: "vertical",
            breakpoints: {
                320: {
                    direction: "horizontal",
                },
                992: {
                    direction: "vertical",
                }
            }
        });
        gallery.mySwiper2 = new Swiper(`.gallery[data-slider-id="${index}"] .mySwiper2`, {
            spaceBetween: 0,
            direction: "vertical",
            loop: true,
            navigation: {
                nextEl: `.gallery[data-slider-id="${index}"] .swiper-button-next`,
                prevEl: `.gallery[data-slider-id="${index}"] .swiper-button-prev`,
            },
            thumbs: {
                swiper:  gallery.mySwiper,
            },
            breakpoints: {
                320: {
                    direction: "horizontal",
                },
                992: {
                    direction: "vertical",
                }
            }
        });

        SlidersArray[index] = gallery
    })

}


Sliders()
gallery()

let mainSlider = document.querySelector(".main-slider")
if(mainSlider) {
    const swiper = new Swiper('.main-slider .swiper-container', {
        loop: true,
        autoplay: {
            delay: 4000,
            disableOnInteraction: false,
            pauseOnMouseEnter: true,
        },
        navigation: {
            nextEl: '.main-slider .slider-arrow-next',
            prevEl: '.main-slider .slider-arrow-prev',
        },
        pagination: {
            el: '.main-slider .slider-fraction',
            type: 'custom',
            renderCustom: (sw, current, total) => {
                return `<span class="slider-fraction-curr">${String(current).padStart(2, '0')}</span><span class="slider-fraction-sep">/</span><span class="slider-fraction-tot">${String(total).padStart(2, '0')}</span>`;
            },
        },
        on: {
            init(sw) {
                initSlideMedia(sw);
                handleActiveSlide(sw);
            },
            slideChangeTransitionEnd(sw) {
                handleActiveSlide(sw);
            },
        },
    });

    function initSlideMedia(sw) {
        sw.slides.forEach((slide) => {
            const media = slide.querySelector('.slide-media');
            const loader = slide.querySelector('.slide-loader');
            if (!media) return;

            const markLoaded = () => {
                media.classList.add('is-loaded');
                loader?.classList.add('is-hidden');
                slide.dataset.loaded = 'true';

                if (slide.classList.contains('swiper-slide-active')) {
                    activateSlide(sw, slide);
                }
            };

            const markError = () => {
                loader?.classList.add('is-hidden');
                slide.dataset.loaded = 'true';
                slide.dataset.error = 'true';

                if (slide.classList.contains('swiper-slide-active')) {
                    activateSlide(sw, slide);
                }
            };

            if (media.tagName === 'IMG') {
                if (media.complete && media.naturalWidth > 0) {
                    markLoaded();
                } else {
                    media.addEventListener('load', markLoaded, { once: true });
                    media.addEventListener('error', markError, { once: true });
                }
            }

            if (media.tagName === 'VIDEO') {
                if (media.readyState >= 2) {
                    markLoaded();
                } else {
                    media.addEventListener('loadeddata', markLoaded, { once: true });
                    media.addEventListener('error', markError, { once: true });
                }
            }
        });
    }

    function handleActiveSlide(sw) {
        sw.autoplay.stop();

        sw.slides.forEach((slide) => {
            const video = slide.querySelector('video.slide-media');
            if (!video) return;

            if (!slide.classList.contains('swiper-slide-active')) {
                video.pause();
                if (video._endedHandler) {
                    video.removeEventListener('ended', video._endedHandler);
                    video._endedHandler = null;
                }
            }
        });

        const activeSlide = sw.slides[sw.activeIndex];
        if (activeSlide.dataset.loaded === 'true') {
            activateSlide(sw, activeSlide);
        }
        // иначе activateSlide вызовется из markLoaded/markError, когда media будет готова
    }

    function activateSlide(sw, slide) {
        // защита от гонки: пока ждали загрузку, слайд мог перестать быть активным
        if (!slide.classList.contains('swiper-slide-active')) return;

        const video = slide.querySelector('video.slide-media');

        if (video) {
            if (slide.dataset.error === 'true') {
                // видео битое — не виснем навсегда, листаем дальше через паузу
                setTimeout(() => {
                    if (slide.classList.contains('swiper-slide-active')) sw.slideNext();
                }, 1500);
                return;
            }

            video.currentTime = 0;
            video.play().catch(() => {});

            const onEnded = () => {
                video.removeEventListener('ended', onEnded);
                video._endedHandler = null;
                sw.slideNext();
            };
            video._endedHandler = onEnded;
            video.addEventListener('ended', onEnded);
        } else {
            // обычный слайд с картинкой — включаем стандартный автоплей свайпера
            sw.autoplay.start();
        }
    }
}
let animatedElements = document.querySelectorAll('.anim-newSing');

let Visible = function(target) {
    // Все позиции элемента
    let targetPosition = {
            top: window.pageYOffset + target.getBoundingClientRect().top,
            left: window.pageXOffset + target.getBoundingClientRect().left,
            right: window.pageXOffset + target.getBoundingClientRect().right,
            bottom: window.pageYOffset + target.getBoundingClientRect().bottom
        },
        // Получаем позиции окна
        windowPosition = {
            top: window.pageYOffset,
            left: window.pageXOffset,
            right: window.pageXOffset + document.documentElement.clientWidth,
            bottom: window.pageYOffset + document.documentElement.clientHeight
        };
    if (targetPosition.bottom - 20 > windowPosition.top &&
        targetPosition.top - 40 < windowPosition.bottom) {
        target.classList.add("in-view")
    }
};

initAnimElements()

window.addEventListener('scroll', function() {
    initAnimElements()
});

function initAnimElements() {
    animatedElements.forEach(el => {
        Visible(el)
    })
}

const odometers = document.querySelectorAll("._number-animation");

const observer = new IntersectionObserver((entries, observer) => {
    entries.forEach(entry => {
        if (entry.isIntersecting) {
            const el = entry.target;
            const targetValue = parseInt(el.getAttribute("data-end"), 10);
            el.innerHTML = targetValue;
            observer.unobserve(el);
        }
    });
}, {
    threshold: 0.5
});

odometers.forEach(el => {
    let format = 'd'

    console.log(el.hasAttribute("data-thousands-separate"))
    if(el.hasAttribute("data-thousands-separate")) {
        // format = '( ddd),dd'
    }
    new Odometer({
        el: el,
        value: 0,
        format,
        theme: 'default'
    });

    observer.observe(el);
});


let body = document.querySelector("body")
let modalTogglers = document.querySelectorAll("[data-modal]")
let modals = document.querySelectorAll(".modal")

modalTogglers.forEach(el => {
    el.onclick = function () {
        let modalId = el.getAttribute("data-modal")
        openModal(modalId)
    }
})

function closeModals() {
    modals.forEach(modal => {
        modal.classList.remove("_active")
        body.classList.remove("fixed-body2")
    })
}

function openModal(modalId) {
    closeModals()
    let modal = document.querySelector(`#${modalId}`)
    let closeButtons = modal.querySelectorAll(`._close-modal`)

    modal.classList.add("_active")
    body.classList.add("fixed-body2")


    closeButtons.forEach(btn => {
        btn.onclick = ()=> {
            modal.classList.remove("_active")
            body.classList.remove("fixed-body2")
        }
    })
}

var getScrollBarSize = (function() {
    var el = window.document.createElement('textarea'), style = {
        'visibility': 'hidden', 'position': 'absolute', 'zIndex': '-2147483647',
        'top': '-1000px', 'left': '-1000px', 'width': '1000px', 'height': '1000px',
        'overflow': 'scroll', 'margin': '0', 'border': '0', 'padding': '0'
    }, support = el.clientWidth !== undefined && el.offsetWidth !== undefined;

    for (var key in style) {
        if (style.hasOwnProperty(key)) {
            el.style[key] = style[key];
        }
    }

    return function() {
        var size = null;
        if (support && window.document.body) {
            window.document.body.appendChild(el);
            size = [el.offsetWidth - el.clientWidth, el.offsetHeight - el.clientHeight];
            window.document.body.removeChild(el);
        }

        document.documentElement.style.setProperty('--scrollWidth', `${size[0]}px`);
        return size;
    };
})();


window.addEventListener('DOMContentLoaded', () => {
    fix100vh();
    window.addEventListener('resize', () => {
        fix100vh();
        getScrollBarSize()
    })

    getScrollBarSize()

    // $('input[type="tel"]').mask('+7 (999) 999-99-99', { autoclear: false }, { placeholder: '+7 (   )    -  -  ' });
})

function fix100vh() {
    let vh = window.innerHeight * 0.01;
    document.documentElement.style.setProperty('--vh', `${vh}px`);
}

